mapper.select:
SELECT t1.ID, t1.PLAN_ID, t1.ROUTE_ID, t1.PATROL_ID, t1.PATROL_NAME, t1.START_DATE, t1.END_DATE, t1.STATUS, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t2.ROUTE_CODE, t2.ROUTE_NAME, t2.ROUTE_LEVEL, t3.PLAN_CODE, t3.PLAN_NAME FROM E_PATROL_TASK t1 LEFT JOIN E_PATROL_ROUTE t2 on t2.ID = t1.ROUTE_ID LEFT JOIN E_PATROL_PLAN t3 on t3.ID = t1.PLAN_ID
AND t1.START_DATE >= TO_DATE(#{startTime}, 'yyyy-MM-dd')
AND t1.START_DATE <= TO_DATE(#{endTime}, 'yyyy-MM-dd')
AND t1.PATROL_NAME LIKE #{patrolNameLike}
AND t1.STATUS = #{status}
ORDER BY t1.CREATE_TIME DESC

SELECT t1.PARENT_ID, t1.EQUIP_ID, t1.CHECK_CONTENT, t1.QUALIFY_CONDITION, t1.CHECK_METHOD, t1.STATUS, t1.IS_ABNORMAL, t1.IS_REPAIR, t1.REMARK, t2.PATROL_NAME, t6.FILE_IDS, t7.STANDARD_NAME, t7.STANDARD_CODE, t3.EQUIP_NAME FROM E_PATROL_TASK_SUB t1 LEFT JOIN E_PATROL_TASK t2 on t2.ID = t1.PARENT_ID LEFT JOIN E_M_EQPT_INFO t3 on t3.ID = t1.EQUIP_ID LEFT JOIN E_PATROL_STANDARD t7 ON t7.EQPT_ID = t1.EQUIP_ID LEFT JOIN ( select BUSINESS_ID, LISTAGG(FILE_ID, ',') WITHIN GROUP ( ORDER BY FILE_ID ) FILE_IDS from SYS_FILE_BUSINESS group by BUSINESS_ID )t6 ON t1.ID = t6.BUSINESS_ID WHERE t1.PARENT_ID = #{id}
AND t1.EQUIP_ID = #{equipId}
AND t3.EQUIP_NAME LIKE #{equipNameLike}
AND t1.STATUS = #{status}

SELECT t1.EQUIP_ID "equipId", t3.EQUIP_NAME "equipName" FROM E_PATROL_TASK_SUB t1 LEFT JOIN E_M_EQPT_INFO t3 on t3.ID = t1.EQUIP_ID WHERE t1.PARENT_ID = #{id}
AND t1.EQUIP_ID = #{equipId}
GROUP BY t1.EQUIP_ID, t3.EQUIP_NAME

mapper.update:
begin

    UPDATE
    E_PATROL_TASK_SUB
    SET
    IS_ABNORMAL = #{item.isAbnormal,jdbcType=INTEGER},
    STATUS = 1,
    IS_REPAIR = #{item.isRepair,jdbcType=INTEGER},
    REMARK = #{item.remark,jdbcType=VARCHAR}

        ID = #{item.id,jdbcType=BIGINT}
    ;

end;

mapper.select:
SELECT distinct t1.ID, t1.PLAN_ID, t1.ROUTE_ID, t1.PATROL_ID, t1.PATROL_NAME, t1.START_DATE, t1.END_DATE, t1.STATUS, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t2.ROUTE_CODE, t2.ROUTE_NAME, t2.ROUTE_LEVEL, t3.PLAN_CODE, t3.PLAN_NAME FROM E_PATROL_TASK t1 LEFT JOIN E_PATROL_ROUTE t2 on t2.ID = t1.ROUTE_ID LEFT JOIN E_PATROL_PLAN t3 on t3.ID = t1.PLAN_ID LEFT JOIN E_PATROL_TASK_SUB t4 on t4.PARENT_ID = t1.ID
AND t1.START_DATE >= TO_DATE(#{startTime}, 'yyyy-MM-dd')
AND t1.START_DATE <= TO_DATE(#{endTime}, 'yyyy-MM-dd')
AND t1.PATROL_NAME LIKE #{patrolNameLike}
AND t2.ROUTE_NAME LIKE #{routeNameLike}
AND t3.PLAN_NAME LIKE #{planNameLike}
and instr( #{status}, t1.STATUS) > 0
and t4.EQUIP_ID = #{equipId}
ORDER BY t1.CREATE_TIME DESC

mapper.update:
UPDATE E_PATROL_TASK
SET
    STATUS = #{status}
WHERE
    ID = #{taskId}
